    SET IDENTITY_INSERT [dbo].[Items] OFF;

    PRINT N'Assign default warehouse to clean items';
    UPDATE [dbo].[Items]
    SET [DefaultWarehouseId] = CASE
        WHEN [ItemType] = N'Công cụ dụng cụ' OR [CategoryId] = 2 THEN 2
        ELSE 1
    END;

    PRINT N'Generate ItemPrices fake/demo data';
    ;WITH PriceBase AS
    (
        SELECT
            i.ItemId,
            CAST(CASE
                WHEN i.ItemType = N'Công cụ dụng cụ' OR i.CategoryId = 2 THEN 750000 + ((i.ItemId % 19) * 125000)
                WHEN i.BaseUomId IN (8, 11, 24, 25) THEN 350000 + ((i.ItemId % 17) * 80000)
                ELSE 45000 + ((i.ItemId % 29) * 12000)
            END AS DECIMAL(18, 2)) AS PurchaseAmount
        FROM [dbo].[Items] i
    )
    INSERT [dbo].[ItemPrices] ([ItemId], [PriceType], [Amount], [Currency], [EffectiveFrom], [EffectiveTo], [IsActive], [CreatedAt])
    SELECT ItemId, N'PURCHASE', PurchaseAmount, N'VND', CAST('2026-01-01' AS date), NULL, 1, @Now FROM PriceBase
    UNION ALL
    SELECT ItemId, N'COST', CAST(PurchaseAmount * 1.05 AS DECIMAL(18, 2)), N'VND', CAST('2026-01-01' AS date), NULL, 1, @Now FROM PriceBase
    UNION ALL
    SELECT ItemId, N'SALE', CAST(PurchaseAmount * 1.25 AS DECIMAL(18, 2)), N'VND', CAST('2026-01-01' AS date), NULL, 1, @Now FROM PriceBase;

    PRINT N'Generate InventoryLots fake/demo data';
    ;WITH StockBase AS
    (
        SELECT
            i.ItemId,
            i.DefaultWarehouseId AS WarehouseId,
            CAST(CASE
                WHEN i.ItemType = N'Công cụ dụng cụ' OR i.CategoryId = 2 THEN 3 + (i.ItemId % 15)
                ELSE 25 + (i.ItemId % 120)
            END AS DECIMAL(18, 3)) AS StockQty,
            CAST(CASE
                WHEN i.ItemType = N'Công cụ dụng cụ' OR i.CategoryId = 2 THEN 750000 + ((i.ItemId % 19) * 125000)
                WHEN i.BaseUomId IN (8, 11, 24, 25) THEN 350000 + ((i.ItemId % 17) * 80000)
                ELSE 45000 + ((i.ItemId % 29) * 12000)
            END * 1.05 AS DECIMAL(18, 2)) AS UnitCost,
            CASE
                WHEN i.DefaultWarehouseId = 2 THEN 6 + (i.ItemId % 3)
                ELSE 1 + (i.ItemId % 5)
            END AS LocationId
        FROM [dbo].[Items] i
    )
    INSERT [dbo].[InventoryLots] ([ItemId], [WarehouseId], [GRNLineId], [ReceiptDate], [Quantity], [UnitCost], [ExpiryDate], [IsActive], [LocationId])
    SELECT
        ItemId,
        WarehouseId,
        NULL,
        DATEADD(DAY, -1 * (ItemId % 90), @Now),
        StockQty,
        UnitCost,
        CASE WHEN WarehouseId = 1 THEN DATEADD(MONTH, 18 + (ItemId % 12), @Now) ELSE NULL END,
        1,
        LocationId
    FROM StockBase;

    PRINT N'Generate InventoryOnHand fake/demo data';
    ;WITH StockBase AS
    (
        SELECT
            i.ItemId,
            i.DefaultWarehouseId AS WarehouseId,
            CAST(CASE
                WHEN i.ItemType = N'Công cụ dụng cụ' OR i.CategoryId = 2 THEN 3 + (i.ItemId % 15)
                ELSE 25 + (i.ItemId % 120)
            END AS DECIMAL(18, 3)) AS StockQty,
            CAST(CASE
                WHEN i.ItemType = N'Công cụ dụng cụ' OR i.CategoryId = 2 THEN 750000 + ((i.ItemId % 19) * 125000)
                WHEN i.BaseUomId IN (8, 11, 24, 25) THEN 350000 + ((i.ItemId % 17) * 80000)
                ELSE 45000 + ((i.ItemId % 29) * 12000)
            END * 1.05 AS DECIMAL(18, 2)) AS UnitCost
        FROM [dbo].[Items] i
    )
    INSERT [dbo].[InventoryOnHand] ([WarehouseId], [ItemId], [OnHandQty], [ReservedQty], [UpdatedAt], [UnitCost])
    SELECT
        WarehouseId,
        ItemId,
        StockQty,
        CAST(CASE WHEN StockQty > 10 THEN ItemId % 4 ELSE 0 END AS DECIMAL(18, 3)),
        @Now,
        UnitCost
    FROM StockBase;

    PRINT N'Generate ItemWarehousePolicy fake/demo data';
    INSERT [dbo].[ItemWarehousePolicy] ([ItemId], [WarehouseId], [MinQty], [ReorderQty])
    SELECT
        i.ItemId,
        i.DefaultWarehouseId,
        CAST(CASE WHEN i.ItemType = N'Công cụ dụng cụ' OR i.CategoryId = 2 THEN 2 ELSE 10 END AS DECIMAL(18, 3)),
        CAST(CASE WHEN i.ItemType = N'Công cụ dụng cụ' OR i.CategoryId = 2 THEN 5 ELSE 30 END AS DECIMAL(18, 3))
    FROM [dbo].[Items] i;

