    UNION ALL SELECT N'Warehouses', COUNT(*) FROM [dbo].[Warehouses]
    UNION ALL SELECT N'StorageLocations', COUNT(*) FROM [dbo].[StorageLocations]
    UNION ALL SELECT N'Companies', COUNT(*) FROM [dbo].[Companies]
    UNION ALL SELECT N'Addresses', COUNT(*) FROM [dbo].[Addresses]
    UNION ALL SELECT N'ItemPrices', COUNT(*) FROM [dbo].[ItemPrices]
    UNION ALL SELECT N'InventoryLots', COUNT(*) FROM [dbo].[InventoryLots]
    UNION ALL SELECT N'InventoryOnHand', COUNT(*) FROM [dbo].[InventoryOnHand]
    UNION ALL SELECT N'ItemWarehousePolicy', COUNT(*) FROM [dbo].[ItemWarehousePolicy];

    SELECT ItemCode, COUNT(*) AS Total
    FROM [dbo].[Items]
    GROUP BY ItemCode
    HAVING COUNT(*) > 1;

    SELECT SupplierCode, COUNT(*) AS Total
    FROM [dbo].[Suppliers]
    GROUP BY SupplierCode
    HAVING COUNT(*) > 1;

    SELECT ReceiverCode, COUNT(*) AS Total
    FROM [dbo].[Receivers]
    GROUP BY ReceiverCode
    HAVING COUNT(*) > 1;

    SELECT WarehouseCode, COUNT(*) AS Total
    FROM [dbo].[Warehouses]
    GROUP BY WarehouseCode
    HAVING COUNT(*) > 1;

    SELECT CompanyCode, COUNT(*) AS Total
    FROM [dbo].[Companies]
    GROUP BY CompanyCode
    HAVING COUNT(*) > 1;

    SELECT WarehouseId, ItemId, COUNT(*) AS Total
    FROM [dbo].[InventoryOnHand]
    GROUP BY WarehouseId, ItemId
    HAVING COUNT(*) > 1;

    COMMIT TRANSACTION;
    PRINT N'Clean item master + base fake data script completed successfully.';
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0
        ROLLBACK TRANSACTION;
    DECLARE @ErrMsg NVARCHAR(4000) = ERROR_MESSAGE();
    DECLARE @ErrSeverity INT = ERROR_SEVERITY();
    DECLARE @ErrState INT = ERROR_STATE();
    RAISERROR(@ErrMsg, @ErrSeverity, @ErrState);
END CATCH;

